'use client';

import { useState, useEffect } from 'react';
import { 
  User, 
  Mail, 
  Phone, 
  Briefcase, 
  CalendarDays,
  IndianRupee,
  Shield,
  MapPin,
  Building
} from 'lucide-react';
import { useStore } from '@/store/useStore';
import { apiClient } from '@/lib/api-client';

interface EmployeeProfile {
  employeeCode: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string | null;
  joiningDate: string;
  salary: number;
  status: string;
  department: { name: string } | null;
  designation: { title: string } | null;
  manager: { firstName: string; lastName: string } | null;
}

export default function ProfilePage() {
  const { user } = useStore();
  const [profile, setProfile] = useState<EmployeeProfile | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (user?.employeeId) {
      apiClient.get(`/api/employees/${user.employeeId}`)
        .then(res => {
          if (res.success) {
            setProfile(res.employee);
          }
        })
        .catch(err => console.error(err))
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, [user]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  if (loading) {
    return (
      <div className="flex h-64 items-center justify-center">
        <div className="flex flex-col items-center gap-2">
          <div className="h-6 w-6 animate-spin rounded-full border-2 border-blue-200 border-t-blue-600"></div>
          <span className="text-xs text-[var(--text-muted)]">Loading profile...</span>
        </div>
      </div>
    );
  }

  // Fallback for Admin who might not have an employee record link
  const displayName = profile ? `${profile.firstName} ${profile.lastName}` : (user?.name || 'Administrator');
  const displayEmail = profile ? profile.email : (user?.email || 'admin@pps.com');
  const displayCode = profile ? profile.employeeCode : 'ADMIN';
  const displayDept = profile?.department?.name || 'Finance';
  const displayDes = profile?.designation?.title || 'System Administrator';

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-xl font-black text-[var(--text-primary)]">My Profile</h2>
        <p className="text-xs text-[var(--text-muted)] mt-0.5">Manage your personal corporate registry credentials</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-4xl">
        
        {/* Left Avatar Card */}
        <div className="glass-card p-6 flex flex-col items-center text-center h-fit hover:transform-none">
          <div className="flex h-24 w-24 items-center justify-center rounded-3xl bg-blue-100 dark:bg-blue-950 text-blue-600 font-bold text-3xl uppercase shadow-lg shadow-blue-500/10">
            {displayName.split(' ').map(n => n[0]).join('')}
          </div>
          
          <h3 className="text-base font-bold text-[var(--text-primary)] mt-4">{displayName}</h3>
          <p className="text-xs text-[var(--text-muted)] font-medium mt-0.5">{displayDes}</p>
          <span className="inline-flex items-center rounded-full bg-blue-50 dark:bg-blue-950/20 px-2.5 py-0.5 text-[10px] font-bold text-blue-600 dark:text-blue-400 border border-blue-100 dark:border-blue-900/10 uppercase tracking-wider mt-3">
            {displayCode}
          </span>

          <div className="w-full border-t border-[var(--card-border)] mt-6 pt-4 text-left space-y-3.5">
            <div className="flex items-center gap-3 text-xs text-[var(--text-secondary)] font-medium">
              <Mail size={16} className="text-blue-500 shrink-0" />
              <span className="truncate">{displayEmail}</span>
            </div>
            {profile?.phone && (
              <div className="flex items-center gap-3 text-xs text-[var(--text-secondary)] font-medium">
                <Phone size={16} className="text-blue-500 shrink-0" />
                <span>{profile.phone}</span>
              </div>
            )}
            <div className="flex items-center gap-3 text-xs text-[var(--text-secondary)] font-medium">
              <MapPin size={16} className="text-blue-500 shrink-0" />
              <span>Mumbai Office, India</span>
            </div>
          </div>
        </div>

        {/* Right Details Panel */}
        <div className="glass-card p-6 md:col-span-2 space-y-6 hover:transform-none">
          <div>
            <h3 className="text-sm font-bold text-[var(--text-primary)]">Employment Details</h3>
            <p className="text-[10px] text-[var(--text-muted)] mt-0.5">Corporate registry parameters and management relations</p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-4 gap-x-6">
            <div className="space-y-1">
              <span className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Department</span>
              <p className="text-xs font-bold text-[var(--text-primary)] flex items-center gap-1.5">
                <Building size={14} className="text-blue-500" />
                {displayDept}
              </p>
            </div>
            <div className="space-y-1">
              <span className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Designation</span>
              <p className="text-xs font-bold text-[var(--text-primary)] flex items-center gap-1.5">
                <Briefcase size={14} className="text-blue-500" />
                {displayDes}
              </p>
            </div>
            <div className="space-y-1">
              <span className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Joining Date</span>
              <p className="text-xs font-bold text-[var(--text-primary)] flex items-center gap-1.5">
                <CalendarDays size={14} className="text-blue-500" />
                {profile ? new Date(profile.joiningDate).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' }) : 'Jan 15, 2024'}
              </p>
            </div>
            <div className="space-y-1">
              <span className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Reporting Manager</span>
              <p className="text-xs font-bold text-[var(--text-primary)] flex items-center gap-1.5">
                <Shield size={14} className="text-blue-500" />
                {profile?.manager ? `${profile.manager.firstName} ${profile.manager.lastName}` : 'Self / Executive Board'}
              </p>
            </div>
          </div>

          <div className="border-t border-[var(--card-border)] pt-6">
            <h3 className="text-sm font-bold text-[var(--text-primary)] mb-4">Salary Structure</h3>
            
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="p-4 rounded-xl border border-[var(--card-border)] bg-slate-50/50 dark:bg-slate-900/10 flex items-center justify-between">
                <div>
                  <span className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">CTC Gross Salary</span>
                  <p className="text-base font-black text-[var(--text-primary)] mt-1">
                    {formatCurrency(profile ? profile.salary : 150000)}
                  </p>
                </div>
                <div className="flex h-9 w-9 items-center justify-center rounded-lg bg-blue-100 dark:bg-blue-950 text-blue-600">
                  <IndianRupee size={18} />
                </div>
              </div>
            </div>
          </div>

        </div>

      </div>
    </div>
  );
}
